mapper.select:
/* IResidentBoardNoticeMapper.selectResidentBoardNoticeCount */ SELECT COUNT(*) FROM apt_ann_board_post aabp INNER JOIN apt_board_instance abi ON aabp.board_no = abi.board_no WHERE aabp.del_yn = 'N' AND abi.use_yn = 'Y' AND abi.board_ty_cd = 'NOTICE' AND abi.apt_cmplex_no = #{aptCmplexNo}
AND aabp.ttl LIKE '%' || #{searchTtl} || '%'
AND TRUNC(aabp.reg_dttm) >= TO_DATE(#{searchStartDt}, 'YYYY-MM-DD')
AND TRUNC(aabp.reg_dttm) <= TO_DATE(#{searchEndDt}, 'YYYY-MM-DD')

/* * 입주민 공지사항 목록 조회 * * ATTACH_FILE JOIN 금지 * → 첨부파일이 2개면 공지글도 2줄로 중복 조회됨. */
SELECT * FROM ( SELECT ROWNUM AS rnum, notice_list.* FROM ( SELECT aabp.ann_no , aabp.board_no , abi.apt_cmplex_no , aabp.ttl , aabp.wrtr_id , TO_CHAR(aabp.reg_dttm, 'YYYY-MM-DD') AS reg_dttm , TO_CHAR(aabp.mdf_dttm, 'YYYY-MM-DD') AS mdf_dttm , NVL(aabp.inq_cnt, 0) AS inq_cnt , aabp.del_yn , aabp.atch_file_id , abi.board_ty_cd , abi.board_nm , aabp.top_fix_yn
/* * 첨부파일 개수만 조회 */ , ( SELECT COUNT(*) FROM attach_file af WHERE TO_CHAR(af.file_group_no) = aabp.atch_file_id ) AS file_cnt
FROM apt_ann_board_post aabp INNER JOIN apt_board_instance abi ON aabp.board_no = abi.board_no
WHERE aabp.del_yn = 'N' AND abi.use_yn = 'Y' AND abi.board_ty_cd = 'NOTICE' AND abi.apt_cmplex_no = #{aptCmplexNo}
AND aabp.ttl LIKE '%' || #{searchTtl} || '%'
AND TRUNC(aabp.reg_dttm) >= TO_DATE(#{searchStartDt}, 'YYYY-MM-DD')
AND TRUNC(aabp.reg_dttm) <= TO_DATE(#{searchEndDt}, 'YYYY-MM-DD')
ORDER BY CASE WHEN aabp.top_fix_yn = 'Y' AND ( SELECT COUNT(*) FROM apt_ann_board_post y INNER JOIN apt_board_instance yb ON y.board_no = yb.board_no WHERE yb.apt_cmplex_no = abi.apt_cmplex_no AND yb.board_ty_cd = 'NOTICE' AND yb.use_yn = 'Y' AND y.del_yn = 'N' AND y.top_fix_yn = 'Y' AND ( y.reg_dttm > aabp.reg_dttm OR ( y.reg_dttm = aabp.reg_dttm AND TO_NUMBER(REGEXP_REPLACE(y.ann_no, '[^0-9]', '')) > TO_NUMBER(REGEXP_REPLACE(aabp.ann_no, '[^0-9]', '')) ) ) ) < 5 THEN 0 ELSE 1 END, aabp.reg_dttm DESC, TO_NUMBER(REGEXP_REPLACE(aabp.ann_no, '[^0-9]', '')) DESC ) notice_list WHERE ROWNUM <= #{endRow} ) WHERE rnum >= #{startRow}

/* * 입주민 공지사항 상세 조회 * * 중요: * selectOne()으로 호출되므로 반드시 1건만 조회되어야 한다. * * 첨부파일 JOIN 금지 * → 첨부파일 개수만큼 게시글이 중복될 수 있음. */
SELECT aabp.ann_no , aabp.board_no , abi.apt_cmplex_no , aabp.ttl , aabp.cn , aabp.wrtr_id , TO_CHAR(aabp.reg_dttm, 'YYYY-MM-DD') AS reg_dttm , TO_CHAR(aabp.mdf_dttm, 'YYYY-MM-DD') AS mdf_dttm , NVL(aabp.inq_cnt, 0) AS inq_cnt , aabp.del_yn , aabp.atch_file_id , abi.board_ty_cd , abi.board_nm , aabp.top_fix_yn
/* * 첨부파일 개수만 조회 */ , ( SELECT COUNT(*) FROM attach_file af WHERE TO_CHAR(af.file_group_no) = aabp.atch_file_id ) AS file_cnt
FROM apt_ann_board_post aabp INNER JOIN apt_board_instance abi ON aabp.board_no = abi.board_no
WHERE aabp.del_yn = 'N' AND abi.use_yn = 'Y' AND abi.board_ty_cd = 'NOTICE' AND abi.apt_cmplex_no = #{aptCmplexNo} AND aabp.ann_no = #{annNo}

mapper.update:
/* IResidentBoardNoticeMapper.updateResidentBoardNoticeInqCnt */
UPDATE apt_ann_board_post
SET inq_cnt = NVL(inq_cnt, 0) + 1
WHERE ann_no = #{annNo}
  AND del_yn = 'N'
  AND board_no IN (
    SELECT board_no
    FROM apt_board_instance
    WHERE apt_cmplex_no = #{aptCmplexNo}
      AND board_ty_cd = 'NOTICE'
      AND use_yn = 'Y'
)
